form:Form.form:Scripts:
		function EditarRegistro()
{
  if (Ctrl("EDIT")?false:true) return false;
  if (!Ctrl("EDIT").GetEnabled()) return false;


  appendFormInMain("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "EDIT_"+Ctrl("LIST").GetSelectAttrValue("c_tipo"), '<DATA ID="'+Ctrl("LIST").GetXValue()+'" PARENT="'+Ctrl("PARENT").GetXValue()+'" />');
  return true;
}

function AgregarRegistro()
{
  if (Ctrl("ADD")?false:true) return false;
  if (!Ctrl("ADD").GetEnabled()) return false;


  appendFormInMain("NucleusRH.Base.Configuracion.Paginas.PAGINA.MAIN.STD.flow", "ADD", '<DATA ID="'+Ctrl("LIST").GetXValue()+'" PARENT="'+Ctrl("PARENT").GetXValue()+'" />');
  return true;
}

function AceptarRegistro()
{
	Ctrl("label").SetXValue(Ctrl("LIST").GetSelectAttrValue("d_pagina"));
	Ctrl("url"  ).SetXValue("./GenFiles/"+GetProxy().AppName()+"/PREVIEW/PAGE."+Ctrl("LIST").GetXValue()+".LANG.html");
	return true;
}
